import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios'; // <--- Bổ sung dòng này
import './LoginPage.css';

function LoginPage({ setAuthStatus }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState(''); // Thêm state để hiển thị lỗi
  const navigate = useNavigate();

  const handleLogin = async (e) => { // <--- Thêm async ở đây
    e.preventDefault();
    setError(''); // Xóa lỗi cũ
    console.log('handleLogin function called.');

    try {
      // <--- THAY THẾ TOÀN BỘ PHẦN NÀY BẰNG GỌI API THỰC TẾ
      const response = await axios.post('http://localhost:10000/api/login', { // <--- Đảm bảo đây là URL đăng nhập backend của bạn
        email,
        password,
      });

      const { token, role } = response.data; // <--- Backend của bạn phải trả về token và role

      // GỌI setAuthStatus VỚI TOKEN VÀ ROLE THỰC TẾ TỪ BACKEND
      setAuthStatus(token, role); 

      console.log('Token after set (via setAuthStatus):', localStorage.getItem('token'));
      console.log('Role after set (via setAuthStatus):', localStorage.getItem('role'));

      navigate('/dashboard');
      console.log('Navigation to /dashboard attempted.');

    } catch (err) {
      console.error('Lỗi đăng nhập:', err);
      // Hiển thị thông báo lỗi phù hợp từ backend nếu có, hoặc lỗi chung
      setError(err.response?.data?.message || 'Đăng nhập thất bại. Vui lòng kiểm tra lại email và mật khẩu.');
    }
  };

  return (
    <div className="login-page">
      <div className="login-container">
        <h2 className="login-title">Đăng nhập</h2>
        {error && <p style={{ color: 'red', textAlign: 'center' }}>{error}</p>} {/* Hiển thị lỗi */}
        <form onSubmit={handleLogin}>
          <div className="login-form-group">
            <label htmlFor="email" className="login-label">E-mail</label>
            <input
              type="email"
              id="email"
              className="login-input"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />
          </div>
          <div className="login-form-group">
            <label htmlFor="password" className="login-label">Mật khẩu</label>
            <input
              type="password"
              id="password"
              className="login-input"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
          </div>
          <button type="submit" className="login-button">Đăng nhập</button>
        </form>
        <p className="login-link">Chưa có tài khoản? <a href="/register">Đăng ký</a></p>

        <div className="login-software-info" translate="no">
          Phiên bản 1.0.0 <br />
          &copy;2025Nguyen Van Phuc&copy;0358.758.358&copy;Phuc88.klvn@gmail.com&copy;
        </div>
      </div>
    </div>
  );
}

export default LoginPage;
